        // fast 해제, dfs 우선
    } else if fast_flag {
        core_cmd = core_cmd + ' --fast'
    }
    if dfs_depth > 0 { core_cmd = core_cmd + ' --dfs ' + to_string(dfs_depth) }
    println('  cmd: ' + core_cmd)
    try {
        let _out = exec('bash', ['-c', core_cmd + ' 2>&1'])
        println(to_string(_out))
    } catch _e {
        println('  [core] 실행 오류: ' + to_string(_e))
    }
}

// ─── Stage 2: modules chain (순차 실행, atlas.n6 누적) ───
if modules_csv != '' {
    let mods = modules_csv.split(',')
    let mut mi: i64 = 0
    while mi < len(mods) {
        let m_raw = mods[mi]
        let m_trim = m_raw.trim()
        mi = mi + 1
        if m_trim == '' { continue }
        // 모듈 이름 sanitization: 영숫자 + underscore 만 허용 (path traversal/injection 차단)
        // gotcha-2 해소 완료: hexa String 대소비교(>=, <=) 미지원 → .contains() 화이트리스트로 교체
        // 이전 코드: _ch >= 'a' && _ch <= 'z' → error[Type]: unsupported binary operation: Str Ge Str
        let _alnum = 'abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789_'
        let mut _safe = true
        let mut _ci: i64 = 0
        while _ci < len(m_trim) {
            let _ch = m_trim[_ci..(_ci + 1)]
            if !_alnum.contains(_ch) { _safe = false }
            _ci = _ci + 1
        }
        if !_safe {
            println('')
            println('--- STAGE: ' + m_trim + ' SKIP (비안전 문자 포함 — 영숫자+_만 허용)')
            continue
        }
        let mod_path = _MODULES_DIR + '/blowup_' + m_trim + '.hexa'
        if !file_exists(mod_path) {
            println('')
            println('--- STAGE: ' + m_trim + ' SKIP (모듈 없음: ' + mod_path + ')')
            continue
        }
        println('')
        println('--- STAGE: blowup_' + m_trim + '.hexa ---')
        // 메모리 제한 2GB로 OOM/SIGKILL 완충
        let mod_cmd = 'ulimit -v 2097152 2>/dev/null; '' + _HEXA_BIN + '' '' + mod_path + '' 2>&1'
        try {
            let _mout = exec('bash', ['-c', mod_cmd])
            println(to_string(_mout))
        } catch _me {
            println('  [' + m_trim + '] 실행 오류 (chain 계속): ' + to_string(_me))
        }
    }
}

// ─── Stage 3: 조립 완료 + health ───
println('')
println('--- compose complete ---')
if file_exists(_HEALTH_HEXA) {
