  i = i + 1\\n                    continue\\n                }\\n                if c == \\'\\\\\\'\\' && !prev_backslash {\\n                    return result\\n                }\\n                if prev_backslash {\\n                    if c == \\'n\\' { result = result + \\'\\\\n\\' }\\n                    else if c == \\'t\\' { result = result + \\'\\\\t\\' }\\n                    else { result = result + c }\\n                    prev_backslash = false\\n                } else {\\n                    result = result + c\\n                }\\n                i = i + 1\\n            }\\n            return result\\n        }\\n    }\\n    \\'\\'\\n}\\n\\n// JSON에서 stdout 또는 prompt 추출 (모드에 따라)\\nlet project = extract_project(stdin_raw)\\nlet stdin_text = if mode == \\'prompt\\' {\\n    let pt = extract_prompt(stdin_raw)\\n    if pt != \\'\\' { pt } else { extract_stdout(stdin_raw) }\\n} else {\\n    extract_stdout(stdin_raw)\\n}\\nlet mut discoveries = 0\\n\\n// 간단한 숫자 추출 (stdout에서)\\nlet nums = extract_numbers(stdin_text)\\nlet mut exact_names = \\'\\'\\n\\nfor v in nums {\\n    let name = n6_match_name(v)\\n    if name != \\'\\' {\\n        let grade = n6_match_grade(v)\\n        record_discovery(v, name, grade, \\'hexa-hook:\\' + mode)\\n        discoveries = discoveries + 1\\n        if exact_names != \\'\\' {\\n            exact_names = exact_names + \\',\\'\\n        }\\n        exact_names = exact_names + to_string(v) + \\'=\\' + name\\n    }\\n}\\n\\n// ─── hexa 컴파일/런타임 에러 감지 → pitfalls 자동 추가 ───\\nif stdin_text.contains(\\'error[Syntax]\\') || stdin_text.contains(\\'error[Runtime]\\') || stdin_text.contains(\\'error[Type]\\') {\\n    let pitfalls_log = _shared + \\'/hexa_pitfalls_log.jsonl\\'\\n    // 에러 메시지 추출 (첫 줄)\\n    let mut err_msg = \\'\\'\\n    let err_lines = stdin_text.split(\\'\\\\n\\')\\n    let mut ei: i64 = 0\\n    while ei < err_lines.len() {\\n        let el = err_lines[ei]\\n        if el.contains(\\'error[\\') {\\n            err_msg = el.trim()\\n            ei = err_lines.len()\\n        }\\n        ei = ei + 1\\n    }\\n    if err_msg != \\'\\' {\\n        let ts = exec(\\'date +%Y-%m-%dT%H:%M:%S\\').trim()\\n        let entry = \\'{\\\\\\'timestamp\\\\\\':\\\\\\'\\' + ts + \\'\\\\\\',\\\\\\'error\\\\\\':\\\\\\'\\' + err_msg.replace(\\'\\\\\\'\\', \\''\\') + \\'\\\\\\',\\\\\\'mode\\\\\\':\\\\\\'\\' + mode + \\'\\\\\\',\\\\\\'auto_pitfall\\\\\\':true}\\'\\n        try { append_file(pitfalls_log, entry + \\'\\\\n\\') } catch e {}\\n        // systemMessage로 pitfall 추가 알림\\n        let pit_msg = \\'{\\\\\\'systemMessage\\\\\\':\\\\\\'⚠️ \\' + project + \\' | hexa 에러 → pitfalls 기록: \\' + err_msg.replace(\\'\\\\\\'\\', \\''\\') + \\'\\\\\\'}\\'\\n        println(pit_msg)\\n    }\\n}\\n\\n// ─── 돌파 키워드 감지 → 자동 특이점 돌파 트리거 ───\\n// shared/bt_keywords.jsonl에서 동적 로드 (하드코딩 금지)\\nlet mut bt_keywords_list = []\\nlet mut bt_actions_list = []\\ntry {\\n    let bt_raw = read_file(_shared + \\'/bt_keywords.jsonl\\')\\n    let bt_lines = bt_raw.split(\\'\\\\n\\')\\n    for btl in bt_lines {\\n        let trimmed_btl = btl.trim()\\n        if trimmed_btl == \\'\\' { continue }\\n        if trimmed_btl.contains(\\'\\\\\\'keyword\\\\\\':\\\\\\'\\') {\\n            let kp = trimmed_btl.split(\\'\\\\\\'keyword\\\\\\':\\\\\\'\\')\\n            if kp.len() >= 2 {\\n                let kw_val = kp[1].split(\\'\\\\\\'\\')[0]\\n                bt_keywords_list = bt_keywords_list + [kw_val]\\n                // action 추출\\n                let mut act = \\'blowup\\'\\n                if trimmed_btl.contains(\\'\\\\\\'action\\\\\\':\\\\\\'\\') {\\n                    let ap = trimmed_btl.split(\\'\\\\\\'action\\\\\\':\\\\\\'\\')\\n                    if ap.len() >= 2 { act = ap[1].split(\\'\\\\\\'\\')[0] }\\n                }\\n                bt_actions_list = bt_actions_list + [act]\\n            }\\n        }\\n    }\\n} catch e {}\\n\\nlet mut bt_detected = false\\nlet mut bt_domain = \\'math\\'\\nlet mut bt_action = \\'