iff = to_int(to_float(now_ts)) - to_int(to_float(last_ts))\\n        if diff < 300 { should_run = false }\\n    } catch e {}\\n\\n    if should_run {\\n        // 쿨다운 기록\\n        try { exec(\\'bash\\', [\\'-c\\', \\'date +%s > \\' + cooldown_file]) } catch e {}\\n\\n        let hexa_bin = exec(\\'printenv HOME\\') + \\'/Dev/hexa-lang/target/release/hexa\\'\\n        let nexus_dir = exec(\\'printenv HOME\\') + \\'/Dev/nexus\\'\\n\\n        if bt_action == \\'blowup_loop\\' {\\n            // 프로젝트별 성장 돌파 → breakthrough.hexa --engine\\n            let breakthrough = nexus_dir + \\'/mk2_hexa/native/breakthrough.hexa\\'\\n            try {\\n                exec(\\'cd \\' + nexus_dir + \\' && \\' + hexa_bin + \\' \\' + breakthrough + \\' --engine auto '\\' + stdin_text.replace(\\''\\', \\'\\') + \\'' >> \\' + _shared + \\'/auto_bt.log 2>&1 &\\')\\n                discoveries = discoveries + 1\\n                if exact_names != \\'\\' { exact_names = exact_names + \\',\\' }\\n                exact_names = exact_names + \\'🔄GROWTH:\\' + bt_domain\\n            } catch e {}\\n        } else {\\n            // 단발 블로업 (seed_engine merge → , 구분자)\\n            let blowup = nexus_dir + \\'/mk2_hexa/native/blowup.hexa\\'\\n            let se = nexus_dir + \\'/mk2_hexa/native/seed_engine.hexa\\'\\n            let mut seeds = \\'\\'\\n            try { seeds = exec(hexa_bin + \\' \\' + se + \\' merge\\').trim().replace(\\'|\\', \\',\\') } catch e3 {}\\n            if seeds.len() == 0 { seeds = \\'6,12,2,4,5,24,7,3,1,8,10,28,36,48,60,120,144,288,496,720\\' }\\n            try {\\n                exec(\\'cd \\' + nexus_dir + \\' && \\' + hexa_bin + \\' \\' + blowup + \\' \\' + bt_domain + \\' 3 --no-graph --fast --seeds '\\' + seeds + \\'' >> \\' + _shared + \\'/auto_bt.log 2>&1 &\\')\\n                discoveries = discoveries + 1\\n                if exact_names != \\'\\' { exact_names = exact_names + \\',\\' }\\n                exact_names = exact_names + \\'🛸BT:\\' + bt_domain