    exact_names = exact_names + \\',\\'\\n        }\\n        exact_names = exact_names + to_string(v) + \\'=\\' + name\\n    }\\n}\\n\\n// ─── hexa 컴파일/런타임 에러 감지 → pitfalls 자동 추가 ───\\nif stdin_text.contains(\\'error[Syntax]\\') || stdin_text.contains(\\'error[Runtime]\\') || stdin_text.contains(\\'error[Type]\\') {\\n    let pitfalls_log = _shared + \\'/hexa_pitfalls_log.jsonl\\'\\n    // 에러 메시지 추출 (첫 줄)\\n    let mut err_msg = \\'\\'\\n    let err_lines = stdin_text.split(\\'\\\\n\\')\\n    let mut ei: i64 = 0\\n    while ei < err_lines.len() {\\n        let el = err_lines[ei]\\n        if el.contains(\\'error[\\') {\\n            err_msg = el.trim()\\n            ei = err_lines.len()\\n        }\\n        ei = ei + 1\\n    }\\n    if err_msg != \\'\\' {\\n        let ts = exec(\\'date +%Y-%m-%dT%H:%M:%S\\').trim()\\n        let entry = \\'{\\\\\\'timestamp\\\\\\':\\\\\\'\\' + ts + \\'\\\\\\',\\\\\\'error\\\\\\':\\\\\\'\\' + err_msg.replace(\\'\\\\\\'\\', \\''\\') + \\'\\\\\\',\\\\\\'mode\\\\\\':\\\\\\'\\' + mode + \\'\\\\\\',\\\\\\'auto_pitfall\\\\\\':true}\\'\\n        try { append_file(pitfalls_log, entry + \\'\\\\n\\') } catch e {}\\n        // systemMessage로 pitfall 추가 알림\\n        let pit_msg = \\'{\\\\\\'systemMessage\\\\\\':\\\\\\'⚠️ \\' + project + \\' | hexa 에러 → pitfalls 기록: \\' + err_msg.replace(\\'\\\\\\'\\', \\''\\') + \\'\\\\\\'}\\'\\n        println(pit_msg)\\n    }\\n}\\n\\n// ─── 돌파 키워드 감지 → 자동 특이점 돌파 트리거 ───\\n// shared/bt_keywords.jsonl에서 동적 로드 (하드코딩 금지)\\nlet mut bt_keywords_list = []\\nlet mut bt_actions_list = []\\ntry {\\n    let bt_raw = read_file(_shared + \\'/bt_keywords.jsonl\\')\\n    let bt_lines = bt_raw.split(\\'\\\\n\\')\\n    for btl in bt_lines {\\n        let trimmed_btl = btl.trim()\\n        if trimmed_btl == \\'\\' { continue }\\n        if trimmed_btl.contains(\\'\\\\\\'keyword\\\\\\':\\\\\\'\\') {\\n            let kp = trimmed_btl.split(\\'\\\\\\'keyword\\\\\\':\\\\\\'\\')\\n            if kp.len() >= 2 {\\n                let kw_val = kp[1].split(\\'\\\\\\'\\')[0]\\n                bt_keywords_list = bt_keywords_list + [kw_val]\\n                // action 추출\\n                let mut act = \\'blowup\\'\\n                if trimmed_btl.contains(\\'\\\\\\'action\\\\\\':\\\\\\'\\') {\\n                    let ap = trimmed_btl.split(\\'\\\\\\'action\\\\\\':\\\\\\'\\')\\n                    if ap.len() >= 2 { act = ap[1].split(\\'\\\\\\'\\')[0] }\\n                }\\n                bt_actions_list = bt_actions_list + [act]\\n            }\\n        }\\n    }\\n} catch e {}\\n\\nlet mut bt_detected = false\\nlet mut bt_domain = \\'math\\'\\nlet mut bt_action = \\'blowup\\'\\n\\nlet mut ki = 0\\nwhile ki < len(bt_keywords_list) {\\n    if stdin_text.contains(bt_keywords_list[ki]) {\\n        bt_detected = true\\n        if ki < len(bt_actions_list) { bt_action = bt_actions_list[ki] }\\n    }\\n    ki = ki + 1\\n}\\n\\n// 도메인 자동 판별 — shared/bt_domains.jsonl에서 동적 로드\\nlet mut domain_lines = []\\ntry {\\n    let raw = exec(\\'cat \\' + _shared + \\'/bt_domains.jsonl 2>/dev/null\\')\\n    domain_lines = raw.split(\\'\\\\n\\')\\n} catch e {}\\n\\nfor dline in domain_lines {\\n    if dline.trim() == \\'\\' { continue }\\n    // 간이 JSON 파싱: \\'domain\\':\\'XXX\\' — split 기반\\n    let mut d_name = \\'\\'\\n    if dline.contains(\\'\\\\\\'domain\\\\\\':\\\\\\'\\') {\\n        let d_parts = dline.split(\\'\\\\\\'domain\\\\\\':\\\\\\'\\')\\n        if d_parts.len() >= 2 {\\n            let d_rest = d_parts[1].split(\\'\\\\\\'\\')\\n            if d_rest.len() >= 1 {\\n                d_name = d_rest[0]\\n            }\\n        }\\n    }\\n    if d_name == \\'\\' { continue }\\n\\n    // \\'keywords\\':[...] — split 기반 키워드 추출\\n    if dline.contains(\\'\\\\\\'keywords\\\\\\':[\\') {\\n        let kw_parts = dline.split(\\'\\\\\\'keywords\\\\\\':[\\')\\n        if kw_parts.len() >= 2 {\\n            let kw_body = kw_parts[1].split(\\']\\')\\n            if kw_body.len() >= 1 {\\n                let kw_items = kw_body[0].split(\\',\\')\\n                for kp in kw_items {\\n                    let kw_clean = kp.trim().replace(\\'\\\\\\'\\', \\'\\')\\n                    if kw_clean != \\'\\' && stdin_text.contains(kw_clean) {\\n                        bt_domain = d_name\\n                    }\\n                }\\n            }\\n        }\\n    }\\n}\\n\\nif bt_detected {\\n    // 쿨다운 체크 (마지막 돌파 후 5분 이내면 스킵)\\n    let cooldown_file = _shared + \\'/.bt_cooldown\\'\\n    let mut should_run = true\\n    try {\\n        let last_ts = exec(\\'cat \\' + cooldown_file).trim()\\n        let now_ts = exec(\\'date +%s\\').trim()\\n        let diff = to_int(to_float(now_ts)) - to_int(to_float(last_ts))\\n        if diff < 300 { should_run = false }\\n    } catch e {}\\n\\n    if should_run {\\n        // 쿨다운 기록\\n        try { exec(\\'bash\\', [\\'-c\\', \\'date +%s > \\' + cooldown_file]) } catch e {}\\n\\n        let hexa_bin = exec(\\'printenv HOME\\') + \\'/Dev/hexa-lang/target/release/hexa\\'\\n        let nexus_dir = exec(\\'printenv HOME\\') + \\'/Dev/nexus\\'\\n\\n        if bt_action == \\'converge\\' {\\n            // 연속돌파/수렴 → breakthrough.hexa --converge\\n            let breakthrough = nexus_dir + \\'/mk2_hexa/native/breakthrough.hexa\\'\\n            try {\\n                exec(\\'ssh -o ConnectTimeout=3 -o BatchMode=yes hetzner 'cd ~/Dev/nexus && ~/Dev/hexa-lang/target/release/hexa mk2_hexa/native/breakthrough.hexa --converge >> shared/auto_bt.log 2>&1 &' 2>/dev/null &\\')\\n                discoveries = discoveries + 1\\n                if exact_names != \\'\\' { exact_names = exact_names + \\',\\' }\\n                exact_names = exact_names + \\'🔄CONVERGE:\\' + bt_domain\\n            } catch e {}\\n        } else if bt_action == \\'blowup_loop\\' {\\n            // 프로젝트별 성장 돌파 → breakthrough.hexa --engine\\n            let breakthrough = nexus_dir + \\'/mk2_hexa/native/breakthrough.hexa\\'\\n            try {\\n                exec(\\'ssh -o ConnectTimeout=3 -o BatchMode=yes hetzner 'cd ~/Dev/nexus && ~/Dev/hexa-lang/target/release/hexa mk2_hexa/native/breakthrough.hexa --engine auto >> shared/auto_bt.log 2>&1 &' 2>/dev/null &\\')\\n                discoveries = discoveries + 1\\n                if exact_names != \\'\\' { exact_names = exact_names + \\',\\' }\\n                exact_names = exact_names + \\'🔄GROWTH:\\' + bt_domain\\n            } catch e {}\\n        } else {\\n            // 단발 블로업 (seed_engine merge → , 구분자)\\n            let blowup = nexus_dir + \\'/mk2_hexa/native/blowup.hexa\\'\\n            let se = nexus_dir + \\'/mk2_hexa/native/seed_engine.hexa\\'\\n            let mut seeds = \\'\\'\\n            try { seeds = exec(hexa_bin + \\' \\' + se + \\' merge\\').trim().replace(\\'|\\', \\',\\') } catch e3 {}\\n            if seeds.len() == 0 { seeds = \\'6,12,2,4,5,24,7,3,1,8,10,28,36,48,60,120,144,288,496,720\\' }\\n            try {\\n                exec(\\'ssh -o ConnectTimeout=3 -o BatchMode=yes hetzner 'cd ~/Dev/nexus && ~/Dev/hexa-lang/target/release/hexa mk2_hexa/native/blowup.hexa \\' + bt_domain + \\' 3 --no-graph --fast --seeds \\\\\\'\\' + seeds + \\'\\\\\\' >> shared/auto_bt.log 2>&1 &' 2>/dev/null &\\')\\n                discoveries = discoveries + 1\\n                if exact_names != \\'\\' { exact_names = exact_names + \\',\\' }\\n                exact_names = exact_names + \\'🛸BT:\\' + bt_domain\\n            } catch e {}\\n        }\\n    }\\n}\\n\\n// ─── 빈공간/미발견 키워드 감지 → gap_finder 자동 실행 ───\\nlet gap_keywords = [\\'빈공간\\', \\'미발견\\', \\'미탐색\\', \\'미지 영역\\', \\'empty space\\', \\'gap\\', \\'DFS\\']\\nlet mut gap_detected = false\\n\\nfor gkw in gap_keywords {\\n    if stdin_text.contains(gkw) {\\n        gap_detected = true\\n    }\\n}\\n\\nif gap_detected {\\n    let gap_cooldown = _shared + \\'/.gap_cooldown\\'\\n    let mut gap_should_run = true\\n    try {\\n        let gap_last = exec(\\'cat \\' + gap_cooldown).trim()\\n        let gap_now = exec(\\'date +%s\\')