 !in_comment {\\n            out = out + result[i]\\n        }\\n        i = i + 1\\n    }\\n    return out\\n}\\n\\nfn fix_semicolons(source: string) {\\n    // 줄 끝 세미콜론 제거\\n    let lines = split(source, \\'\\\\n\\')\\n    let mut fixed = []\\n    for line in lines {\\n        let trimmed = trim(line)\\n        if ends_with(trimmed, \\';\\') {\\n            // for 루프 안의 세미콜론은 유지 (C-style for)\\n            if !contains(line, \\'for \\') {\\n                let without = slice(trimmed, 0, len(trimmed) - 1)\\n                // 원본 들여쓰기 유지\\n                let indent = len(line) - len(trim_start(line))\\n                let spaces = repeat(\\' \\', indent)\\n                fixed = push(fixed, spaces + without)\\n                continue\\n            }\\n        }\\n        fixed = push(fixed, line)\\n    }\\n    return join(fixed, \\'\\\\n\\')\\n}\\n\\nfn fix_array_type(source: string) {\\n    // \\': [int]\\' -> \\': array\\'  (파서가 아직 미지원일 때 우회)\\n    let mut result = source\\n    result = replace(result, \\': [int]\\', \\': array\\')\\n    result = replace(result, \\': [i64]\\', \\': array\\')\\n    result = replace(result, \\': [float]\\', \\': array\\')\\n    result = replace(result, \\': [string]\\', \\': array\\')\\n    result = replace(result, \\': [bool]\\', \\': array\\')\\n    return result\\n}\\n\\n// ── 메인 로직 ──────────────────────────────────────────\\n\\nif mode == \\'--scan\\' {\\n    // 디렉토리 전체 스캔\\n    let dir = args[2]\\n    let files = glob(dir + \\'/*.hexa\\')\\n    let mut issues = []\\n\\n    for file in files {\\n        let source = read_file(file)\\n        let mut found = []\\n\\n        if contains(source, \\'/*\\') { found = push(found, \\'G3:block_comment\\') }\\n        if contains(source, \\'; \\') || ends_with(trim(source), \\';\\') { found = push(found, \\'G4:semicolon\\') }\\n        if contains(source, \\': [int]\\') || contains(source, \\': [i64]\\') || contains(source, \\': [string]\\') {\\n            found = push(found, \\'G2:array_type\\')\\n        }\\n        if contains(source, \\'-> (\\') { found = push(found, \\'G1:tuple_return\\') }\\n\\n        if len(found) > 0 {\\n            print(file + \\' → \\' + join(found, \\', \\'))\\n            issues = push(issues, [file, found])\\n        }\\n    }\\n\\n    print(\\'\\\\n총 \\' + str(len(issues)) + \\' 파일에 문법 이슈\\')\\n    exit(0)\\n}\\n\\nif mode == \\'--fix\\' {\\n    // 단일 파일 자동 수정\\n    let file = args[2]\\n    let source = read_file(file)\\n    let mut fixed = source\\n    let mut fixes = []\\n\\n    // G3: block comments\\n    if contains(fixed, \\'/*\\') {\\n        fixed = fix_block_comments(fixed)\\n        fixes = push(fixes, \\'G3:block_comment\\')\\n    }\\n\\n    // G4: semicolons\\n    if contains(fixed, \\';\\') {\\n        fixed = fix_semicolons(fixed)\\n        fixes = push(fixes, \\'G4:semicolon\\')\\n    }\\n\\n    // G2: array types (우회)\\n    if contains(fixed, \\': [\\') {\\n        fixed = fix_array_type(fixed)\\n        fixes = push(fixes, \\'G2:array_type→array\\')\\n    }\\n\\n    if len(fixes) > 0 {\\n        write_file(file, fixed)\\n        print(\\'🔧 \\' + file + \\' → \\' + join(fixes, \\', \\'))\\n    } else {\\n        print(\\'✅ \\' + file + \\' — 이슈 없음\\')\\n    }\\n    exit(0)\\n}\\n\\nif mode == \\'--fix-all\\' {\\n    // 디렉토리 전체 자동 수정\\n    let dir = args[2]\\n    let files = glob(dir + \\'/*.hexa\\')\\n    let mut total_fixes = 0\\n\\n    for file in files {\\n        let source = read_file(file)\\n        let mut fixed = source\\n        let mut fixes = []\\n\\n        if contains(fixed, \\'/*\\') {\\n            fixed = fix_block_comments(fixed)\\n            fixes = push(fixes, \\'G3\\')\\n        }\\n        if contains(fixed, \\';\\') {\\n            fixed = fix_semicolons(fixed)\\n            fixes = push(fixes, \\'G4\\')\\n        }\\n        if contains(fixed, \\': [\\') {\\n            fixed = fix_array_type(fixed)\\n            fixes = push(fixes, \\'G2\\')\\n        }\\n\\n        if len(fixes) > 0 {\\n            write_file(file, fixed)\\n            print(\\'🔧 \\' + file + \\' → \\' + join(fixes, \\', \\'))\\n            total_fixes = total_fixes + 1\\n        }\\n    }\\n    print(\\'\\\\n총 \\' + str(total_fixes) + \\' 파일 수정 완료\\')\\n    exit(0)\\n}\\n\\n// 기본: 에러 텍스트 분석\\nlet file = args[1]\\nlet error_text = if len(args) >= 3 { args[2] } else { \\'\\' }\\n\\nif error_text != \\'\\' {\\n    let info = parse_error(error_text)\\n    let err_file = info[0]\\n    let err_msg = info[1]\\n\\n    // 자동 수정 가능한 패턴 감지\\n    if contains(err_msg, \\'Semicolon\\') {\\n        print(\\'🔧 G4 autofix: semicolon → \\' + err_file)\\n        let src = read_file(err_file)\\n        write_file(err_file, fix_semicolons(src))\\n    } else if contains(err_msg, \\'block comment\\') || contains(err_msg, \\'/*\\') {\\n        print(\\'🔧 G3 autofix: block comment → \\' + err_file)\\n        let src = read_file(err_file)\\n        write_file(err_file, fix_block_comments(src))\\n    } else if contains(err_msg, \\'-> (\\') {\\n        print(\\'⚠️ G1: tuple return — 컴파일러 수정 필요 (workaround: struct 반환)\\')\\n    } else {\\n        print(\\'❓ 알 수 없는 문법 오류: \\' + err_msg)\\n    }\\n}','newString':'// self/grammar_autofix.hexa — Hexa 문법 오류 자동 감지+수정\\n// 모든 수정에 claude code cli 호출 — AI가 컨텍스트 이해하고 수정\\n//\\n// 사용:\\n//   hexa grammar_autofix.hexa --catch \\'error[Syntax]: ...\\' file.hexa\\n//   hexa grammar_autofix.hexa --scan dir/\\n//   hexa grammar_autofix.hexa --fix file.hexa\\n//   hexa grammar_autofix.hexa --fix-all dir/\\n\\nlet args = argv()\\nif len(args) < 2 {\\n    eprintln(\\'usage: grammar_autofix.hexa --catch <error> <file>\\')\\n    eprintln(\\'       grammar_autofix.hexa --scan <dir>\\')\\n    eprintln(\\'       grammar_autofix.hexa --fix <file>\\')\\n    eprintln(\\'       grammar_autofix.hexa --fix-all <dir>\\')\\n    exit(1)\\n}\\n\\nlet mode = args[1]\\nlet _home = exec(\\'printenv HOME\\').trim()\\nlet _hexa = _home + \\'/Dev/hexa-lang\\'\\nlet _rules = _hexa + \\'/shared/hexa_grammar_issues.jsonl\\'\\n\\n// ── claude code cli 호출 ────────────────────────────────\\nfn claude_fix(file: string, error: string) {\\n    let prompt = \\'hexa 문법 오류 자동 수정. \\' +\\n        \\'에러: \\' + error + \\' \\' +\\n        \\'파일: \\' + file + \\' \\' +\\n        \\'규칙: \\' + _rules + \\' 참조. \\' +\\n        \\'수정 후 원본 의미 100% 보존. 최소 수정만. 설명 없이 수정만.\\'\\n    let cmd = \\'claude -p '\\' + prompt + \\'' --allowedTools Read,Edit --max-turns 3 2>/dev/null\\'\\n    let result = exec(cmd)\\n    print(\\'🤖 \\' + file + \\' → claude fix 완료\\')\\n    return result\\n}\\n\\nfn claude_scan_fix(file: string) {\\n    let prompt = \\'이 hexa 파일을 파싱 가능하도록 문법 수정. \\' +\\n        \\'파일: \\' + file + \\' \\' +\\n        \\'알려진 이슈: /* block comments */ 제거, 줄끝 ; 제거, \\' +\\n        \\'-> (T,T) 튜플반환을 struct/배열 반환으로, : [T] 를 : array 로. \\' +\\n        \\'수정 후 원본 로직 100% 보존. 설명 없이 수정만.\\'\\n    let cmd = \\'claude -p '\\' + prompt + \\'' --allowedTools Read,Edit --max-turns 5 2>/dev/null\\'\\n    let result = exec(cmd)\\n    return result\\n}\\n\\n// ── 에러 감지 (빠른 사전 스캔) ──────────────────────────\\nfn detect_issues(source: string) {\\n    let mut found = []\\n    if contains(source, \\'/*\\') { found = push(found, \\'G3:block_comment\\') }\\n    if contains(source, \\'-> (\\') { found = push(found, \\'G1:tuple_return\\') }\\n\\n    let lines = split(source, \\'\\\\n\\')\\n    for line in lines {\\n        let t = trim(line)\\n        if ends_with(t, \\';\\') && !contains(t, \\'for \\') && !contains(t, \\'//\\') {\\n            found = push(found, \\'G4:semicolon\\')\\n            break\\n        }\\n    }\\n\\n    if contains(source, \\': [int]\\') || contains(source, \\': [i64]\\') ||\\n       contains(source, \\': [float]\\') || contains(source, \\': [string]\\') ||\\n       contains(source, \\': [bool]\\') {\\n        found = push(found, \\'G2:array_type\\')\\n    }\\n    return found\\n}\\n\\n// ── --catch: PostToolUse hook 에서 호출 ─────────────────\\nif mode == \\'--catch\\' {\\n    if len(args) < 4 {\\n        eprintln(\\'usage: --catch <error_msg> <file>\\')\\n        exit(1)\\n    }\\n    let error = args[2]\\n    let file = args[3]\\n    if !contains(error, \\'error[\\') { exit(0) }\\n\\n    print(\\'🔧 grammar-catch: \\' + file)\\n    claude_fix(file, error)\\n    exit(0)\\n}\\n\\n// ── --scan: 디렉토리 스캔 (수정 안 함) ──────────────────\\nif mode == \\'--scan\\' {\\n    let dir = args[2]\\n    let files = glob(dir + \\'/*.hexa\\')\\n    let mut issue_count = 0\\n\\n    for file in files {\\n        let source = read_file(file)\\n        let found = detect_issues(source)\\n        if len(found) > 0 {\\n            print(file + \\' → \\' + join(found, \\', \\'))\\n            issue_count = issue_count + 1\\n        }\\n    }\\n    print(\\'\\\\n총 \\' + str(issue_count) + \\' 파일에 문법 이슈\\')\\n    exit(0)\\n}\\n\\n// ── --fix: 단일 파일 claude 수정 ────────────────────────\\nif mode == \\'--fix\\' {\\n    let file = args[2]\\n    let source = read_file(file)\\n    let found = detect_issues(source)\\n\\n    if len(found) == 0 {\\n        print(\\'✅ \\' + file + \\' — 이슈 없음\\')\\n        exit(0)\\n    }\\n\\n    print(\\'🔍 \\' + file + \\' → \\' + join(found, \\', \\'))\\n    claude_scan_fix(file)\\n    print(\\'🤖 \\' + file + \\' → claude fix 완료\\')\\n    exit(0)\\n}\\n\\n// ── --fix-all: 디렉토리 전체 claude 수정 ────────────────\\nif mode == \\'--fix-all\\' {\\n    let dir = args[2]\\n    let files = glob(dir + \\'/*.hexa\\')\\n    let mut total = 0\\n\\n    for file in files {\\n        let source = read_file(file)\\n        let found = detect_issues(source)\\n        if len(found) > 0 {\\n            print(\\'🔍 \\' + file + \\' → \\' + join(found, \\', \\'))\\n            claude_scan_fix(file)\\n            print(\\'🤖 \\' + file + \\' done\\')\\n            total = total + 1\\n        }\\n    }\\n    print(\\'\\\\n총 \\' + str(total) + \\' 파일 claude 수정 완료\\')\\n    exit(0)\\n}\\n\\n// ── 기본: 에러 텍스트 직접 전달 ─────────────────────────\\nlet file = args[1]\\nlet error_text = if len(args) >= 3 { args[2] } else { \\'\\' }\\n\\nif error_text != \\'\\' {\\n    claude_fix(file, error_text)\\n} else {\\n    // 에러 없이 파일만 → 스캔+수정\\n    let source = read_file(file)\\n    let found = detect_issues(source)\\n    if len(found) > 0 {\\n        print(\\'🔍 \\' + join(found, \\', \\'))\\n        claude_scan_fix(file)\\n        print(\\'🤖 완료\\')\\n    } else {\\n        print(\\'✅ 이슈 없음\\')\\n    }\\n}','originalFile':'// self/grammar_autofix.hexa — Hexa 문법 오류 자동 감지+수정\\n// Claude Code PostToolUse hook에서 호출\\n// 사용: hexa self/grammar_autofix.hexa <file.hexa> <error_output>\\n//   또는 파이프: hexa run file.hexa 2>&1 | hexa self/grammar_autofix.hexa --stdin\\n\\nlet args = argv()\\nif len(args) < 2 {\\n    eprintln(\\'usage: grammar_autofix.hexa <file> [error_text]\\')\\n    eprintln(\\'       grammar_autofix.hexa --scan <dir>\\')\\n    exit(1)\\n}\\n\\nlet mode = args[1]\\n\\n// ── 패턴 정의 ──────────────────────────────────────────\\n// 각 패턴: [id, regex_hint, description, auto_fixable]\\nlet patterns = [\\n    [\\'G1\\', \\'-> (\\', \\'튜플 반환타입 -> (T, T)\\', false],\\n    [\\'G2\\', \\': [\\',  \\'배열 타입 어노테이션 : [T]\\', true],\\n    [\\'G3\\', \\'/*\\',   \\'블록 주석 /* ... */\\', true],\\n    [\\'G4\\', \\';\\',    \\'불필요한 세미콜론\\', true],\\n    [\\'G5\\', \\'if { Struct{}\\', \\'if 블록 내 struct literal 충돌\\', false]\\n]\\n\\n// ── 에러 파싱 ──────────────────────────────────────────\\nfn parse_error(line: string) {\\n    // error[Syntax]: message --> file:line:col\\n    let mut file = \\'\\'\\n    let mut msg = \\'\\'\\n    let mut err_line = 0\\n    let mut err_col = 0\\n\\n    if contains(line, \\'-->\\') {\\n        let parts = split(line, \\'-->\\')\\n        if len(parts) >= 2 {\\n            msg = trim(parts[0])\\n            let loc = trim(parts[1])\\n            let loc_parts = split(loc, \\':\\')\\n            if len(loc_parts) >= 3 {\\n                file = loc_parts[0]\\n                err_line = int(loc_parts[1])\\n                err_col = int(loc_parts[2])\\n            }\\n        }\\n    }\\n    return [file, msg, str(err_line), str(err_col)]\\n}\\n\\n// ── 자동 수정 함수들 ──────────────────────────────────\\nfn fix_block_comments(source: string) {\\n    // /* ... */ 제거 (중첩 미지원, 단순 패턴)\\n    let mut result = source\\n    let mut i = 0\\n    let mut out = \\'\\'\\n    let mut in_comment = false\\n    let mut depth = 0\\n\\n    while i < len(result) {\\n        if i + 1 < len(result) {\\n            if result[i] == \\'/\\' && result[i + 1] == \\'*\\' {\\n                depth = depth + 1\\n                in_comment = true\\n                i = i + 2\\n                continue\\n            }\\n            if result[i] == \\'*\\' && result[i + 1] == \\'/\\' {\\n                depth = depth - 1\\n                if depth == 0 { in_comment = false }\\n                i = i + 2\\n                continue\\n            }\\n        }\\n        if !in_comment {\\n            out = out + result[i]\\n        }\\n        i = i + 1\\n    }\\n    return out\\n}\\n\\nfn fix_semicolons(source: string) {\\n    // 줄 끝 세미콜론 제거\\n    let lines = split(source, \\'\\\\n\\')\\n    let mut fixed = []\\n    for line in lines {\\n        let trimmed = trim(line)\\n        if ends_with(trimmed, \\';\\') {\\n            // for 루프 안의 세미콜론은 유지 (C-style for)\\n            if !contains(line, \\'for \\') {\\n                let without = slice(trimmed, 0, len(trimmed) - 1)\\n                // 원본 들여쓰기 유지\\n                let indent = len(line) - len(trim_start(line))\\n                let spaces = repeat(\\' \\', indent)\\n                fixed = push(fixed, spaces + without)\\n                continue\\n            }\\n        }\\n        fixed = push(fixed, line)\\n    }\\n    return join(fixed, \\'\\\\n\\')\\n}\\n\\nfn fix_array_type(source: string) {\\n    // \\': [int]\\' -> \\': array\\'  (파서가 아직 미지원일 때 우회)\\n    let mut result = source\\n    result = replace(result, \\': [int]\\', \\': array\\')\\n    result = re