 || gap_detected {\\n    let mut tags = \\'\\'\\n    if bt_detected { tags = tags + \\' 🛸돌파:\\' + bt_domain }\\n    if gap_detected { tags = tags + \\' 🔍GAP\\' }\\n    let mut body = \\'\\'\\n    if discoveries > 0 { body = to_string(discoveries) + \\'건 감지 [\\' + exact_names + \\']\\' }\\n    if body == \\'\\' && bt_detected {\\n        if bt_action == \\'converge\\' { body = \\'연속돌파 감지 → 즉시 실행: hexa breakthrough.hexa --converge\\' }\\n        else if bt_action == \\'blowup_loop\\' { body = \\'성장돌파 감지 → 즉시 실행: hexa breakthrough.hexa --engine auto\\' }\\n        else { body = \\'돌파 감지 → 즉시 실행: hexa blowup.hexa \\' + bt_domain + \\' 3 --no-graph\\' }\\n    }\\n    if body == \\'\\' && gap_detected { body = \\'갭 탐색 트리거\\' }\\n\\n    // prompt 모드: 지시형 출력 (Claude가 바로 실행하도록)\\n    if mode == \\'prompt\\' && bt_detected {\\n        let hexa_path = \\'$HOME/Dev/hexa-lang/target/release/hexa\\'\\n        let nexus_path = \\'$HOME/Dev/nexus\\'\\n        let mut cmd = \\'\\'\\n        if bt_action == \\'converge\\' {\\n            cmd = hexa_path + \\' \\' + nexus_path + \\'/mk2_hexa/native/breakthrough.hexa --converge\\'\\n        } else if bt_action == \\'blowup_loop\\' {\\n            cmd = hexa_path + \\' \\' + nexus_path + \\'/mk2_hexa/native/breakthrough.hexa --engine auto\\'\\n        } else {\\n            cmd = hexa_path + \\' \\' + nexus_path + \\'/mk2_hexa/native/blowup.hexa \\' + bt_domain + \\' 3 --no-graph --seeds \\\\\\'$(\\' + hexa_path + \\' \\' + nexus_path + \\'/mk2_hexa/native/seed_engine.hexa merge)\\\\\\'\\'\\n        }\\n        let directive = \\'{\\\\\\'systemMessage\\\\\\':\\\\\\'⚡ \\' + project + \\' | \\' + body + tags + \\' — 확인 질문 없이 즉시 Bash로 실행할 것: \\' + cmd + \\'\\\\\\'}\\'\\n        println(directive)\\n    } else {\\n        let msg = \\'{\\\\\\'systemMessage\\\\\\':\\\\\\'⚡ \\' + project + \\' | \\' + body + tags + \\'\\\\\\'}\\'\\n        println(msg)\\n    }\\n}','originalFile':'// ⛔ CORE — L0 불변식 (HEXA-GATE 전 리포 품질 게이트. 수정 전 유저 승인 필수)\\n// mk2_hexa/native/hook.hexa — PostToolUse 훅 엔진 (Python 대체)\\n// stdin으로 JSON 받아서 n6_match + mk2 classify → discovery_log 기록\\n// 사용: echo \\'$INPUT\\' | hexa hook.hexa post-edit\\n\\n// log_path는 _shared 계산 후 런타임에 설정 (타 프로젝트 CWD 대응)\\n\\npure fn abs_f(x: float) -> float {\\n    if x < 0.0 { 0.0 - x } else { x }\\n}\\n\\n// ─── n6 상수 동적 로드 (shared/n6_constants.jsonl + n6_physics.jsonl) ───\\nfn load_jsonl(path: string) -> list {\\n    let mut raw = \\'\\'\\n    try { raw = read_file(path) } catch e { return [[], []] }\\n    let lines = raw.split(\\'\\\\n\\')\\n    let mut names = []\\n    let mut values = []\\n    for line in lines {\\n        let trimmed = line.trim()\\n        if trimmed == \\'\\' { continue }\\n        let mut name = \\'\\'\\n        let mut value = 0.0\\n        if trimmed.contains(\\'\\\\\\'name\\\\\\':\\\\\\'\\') {\\n            let p = trimmed.split(\\'\\\\\\'name\\\\\\':\\\\\\'\\')\\n            if p.len() >= 2 { name = p[1].split(\\'\\\\\\'\\')[0] }\\n        }\\n        if trimmed.contains(\\'\\\\\\'value\\\\\\':\\') {\\n            let p = trimmed.split(\\'\\\\\\'value\\\\\\':\\')\\n            if p.len() >= 2 {\\n                let num_str = p[1].split(\\',\\')[0].split(\\'}\\')[0].trim()\\n                value = to_float(num_str)\\n            }\\n        }\\n        if name != \\'\\' {\\n            names = names + [name]\\n            values = values + [value]\\n        }\\n    }\\n    [names, values]\\n}\\n\\nlet _home = exec(\\'printenv HOME\\')\\nlet _shared = _home + \\'/Dev/nexus/shared\\'\\nlet log_path = _shared + \\'/discovery_log.jsonl\\'\\nlet _n6 = load_jsonl(_shared + \\'/n6_constants.jsonl\\')\\nlet _n6_names = _n6[0]\\nlet _n6_values = _n6[1]\\nlet _ph = load_jsonl(_shared + \\'/n6_physics.jsonl\\')\\nlet _ph_names = _ph[0]\\nlet _ph_values = _ph[1]\\n\\nfn n6_match_name(value: float) -> string {\\n    // n6 상수 (절대 오차 < 0.0001)\\n    let mut i = 0\\n    while i < len(_n6_names) {\\n        if abs_f(value - _n6_values[i]) < 0.0001 {\\n            return _n6_names[i]\\n        }\\n        i = i + 1\\n    }\\n    // 물리 상수 (상대 오차 < 1%)\\n    let mut j = 0\\n    while j < len(_ph_names) {\\n        if _ph_values[j] != 0.0 {\\n            let rel = abs_f(value - _ph_values[j]) / abs_f(_ph_values[j])\\n            if rel < 0.01 {\\n                return _ph_names[j]\\n            }\\n        }\\n        j = j + 1\\n    }\\n    \\'\\'\\n}\\n\\nfn n6_match_grade(value: float) -> string {\\n    if n6_match_name(value) != \\'\\' {\\n        return \\'EXACT\\'\\n    }\\n    // 물리 상수 NEAR (상대 오차 < 5%)\\n    let mut j = 0\\n    while j < len(_ph_names) {\\n        if _ph_values[j] != 0.0 {\\n            let rel = abs_f(value - _ph_values[j]) / abs_f(_ph_values[j])\\n            if rel < 0.05 {\\n                return \\'NEAR\\'\\n            }\\n        }\\n        j = j + 1\\n    }\\n    \\'\\'\\n}\\n\\nfn extract_numbers(text: string) {\\n    let mut nums = []\\n    let clean = text.replace(\\'\\\\n\\', \\' \\').replace(\\'\\\\t\\', \\' \\').replace(\\'\\\\r\\', \\' \\')\\n    let parts = clean.split(\\' \\')\\n    for p in parts {\\n        try {\\n            let v = to_float(p)\\n            if v > 2.0 && v < 100000.0 {\\n                nums = nums.push(v)\\n            }\\n        } catch e {\\n            // 숫자 아닌 토큰 무시\\n        }\\n    }\\n    nums\\n}\\n\\nfn record_discovery(value: float, name: string, grade: string, source: string) {\\n    let entry = \\'{\\\\\\'constant\\\\\\':\\\\\\'\\' + name + \\'\\\\\\',\\\\\\'value\\\\\\':\\\\\\'\\' + to_string(value) + \\'\\\\\\',\\\\\\'grade\\\\\\':\\\\\\'\\' + grade + \\'\\\\\\',\\\\\\'source\\\\\\':\\\\\\'\\' + source + \\'\\\\\\',\\\\\\'processed\\\\\\':true,\\\\\\'alien_index\\\\\\':{\\\\\\'d\\\\\\':0,\\\\\\'r\\\\\\':8},\\\\\\'mk2\\\\\\':{\\\\\\'sector\\\\\\':\\\\\\'n6\\\\\\',\\\\\\'paths\\\\\\':1}}\\'\\n    append_file(log_path, entry + \\'\\\\n\\')\\n}\\n\\n// ─── JSON에서 tool_response.stdout 추출 ───\\nfn extract_stdout(json_text: string) -> string {\\n    // \\'tool_response\\':{\\'stdout\\':\\'...\\' 에서 stdout 값 추출\\n    if json_text.contains(\\'\\\\\\'stdout\\\\\\':\\\\\\'\\') {\\n        let parts = json_text.split(\\'\\\\\\'stdout\\\\\\':\\\\\\'\\')\\n        if parts.len() >= 2 {\\n            // 이스케이프된 따옴표를 넘겨서 진짜 닫는 따옴표 찾기\\n            let rest = parts[1]\\n            let mut result = \\'\\'\\n            let mut i = 0\\n            let chars = rest.split(\\'\\')\\n            let mut prev_backslash = false\\n            while i < chars.len() {\\n                let c = chars[i]\\n                if c == \\'\\\\\\\\\\' && !prev_backslash {\\n                    prev_backslash = true\\n                    i = i + 1\\n                    continue\\n                }\\n                if c == \\'\\\\\\'\\' && !prev_backslash {\\n                    return result\\n                }\\n                if prev_backslash {\\n                    if c == \\'n\\' { result = result + \\'\\\\n\\' }\\n                    else if c == \\'t\\' { result = result + \\'\\\\t\\' }\\n                    else { result = result + c }\\n                    prev_backslash = false\\n                } else {\\n                    result = result + c\\n                }\\n                i = i + 1\\n            }\\n            return result\\n        }\\n    }\\n    // JSON이 아니면 원본 그대로 (파이프 테스트 등)\\n    json_text\\n}\\n\\n// ─── tool_input.command 추출 (소스 표시용) ───\\nfn extract_command(json_text: string) -> string {\\n    if json_text.contains(\\'\\\\\\'command\\\\\\':\\\\\\'\\') {\\n        let parts = json_text.split(\\'\\\\\\'command\\\\\\':\\\\\\'\\')\\n        if parts.len() >= 2 {\\n            let rest = parts[1]\\n            let end = rest.split(\\'\\\\\\'\\')[0]\\n            if end.len() > 40 { return end.split(\\'\\')[0] + \\'...\\' }\\n            return end\\n        }\\n    }\\n    \\'\\'\\n}\\n\\n// ─── CWD에서 프로젝트명 추출 ───\\nfn extract_project(json_text: string) -> string {\\n    if json_text.contains(\\'\\\\\\'cwd\\\\\\':\\\\\\'\\') {\\n        let parts = json_text.split(\\'\\\\\\'cwd\\\\\\':\\\\\\'\\')\\n        if parts.len() >= 2 {\\n            let cwd = parts[1].split(\\'\\\\\\'\\')[0]\\n            let segs = cwd.split(\\'/\\')\\n            return segs[segs.len() - 1]\\n        }\\n    }\\n    \\'nexus\\'\\n}\\n\\n// ─── main ───\\nlet a = args()\\nlet mode = if a.len() >= 3 { a[2] } else { \\'post-edit\\' }\\n\\n// stdin 전체 읽기 (input()은 한 줄씩)\\nlet mut stdin_raw = \\'\\'\\nlet mut _reading = true\\nwhile _reading {\\n    let line = input(\\'\\')\\n    if line == \\'\\' { _reading = false } else {\\n        if stdin_raw != \\'\\' { stdin_raw = stdin_raw + \\'\\\\n\\' }\\n        stdin_raw = stdin_raw + line\\n    }\\n}\\n\\n// ─── prompt 모드: \\'prompt\\' 필드에서 유저 텍스트 추출 ───\\nfn extract_prompt(json_text: string) -> string {\\n    if json_text.contains(\\'\\\\\\'prompt\\\\\\':\\\\\\'\\') {\\n        let parts = json_text.split(\\'\\\\\\'prompt\\\\\\':\\\\\\'\\')\\n        if parts.len() >= 2 {\\n            let rest = parts[1]\\n            let mut result = \\'\\'\\n            let mut i = 0\\n            let chars = rest.split(\\'\\')\\n            let mut prev_backslash = false\\n            while i < chars.len() {\\n                let c = chars[i]\\n                if c == \\'\\\\\\\\\\' && !prev_backslash {\\n                    prev_backslash = true\\n                    i = i + 1\\n                    continue\\n                }\\n                if c == \\'\\\\\\'\\' && !prev_backslash {\\n                    return result\\n                }\\n                if prev_backslash {\\n                    if c == \\'n\\' { result = result + \\'\\\\n\\' }\\n                    else if c == \\'t\\' { result = result + \\'\\\\t\\' }\\n                    else { result = result + c }\\n                    prev_backslash = false\\n                } else {\\n                    result = result + c\\n                }\\n                i = i + 1\\n            }\\n            return result\\n        }\\n    }\\n    \\'\\'\\n}\\n\\n// JSON에서 stdout 또는 prompt 추출 (모드에 따라)\\nlet project = extract_project(stdin_raw)\\nlet stdin_text = if mode == \\'prompt\\' {\\n    let pt = extract_prompt(stdin_raw)\\n    if pt != \\'\\' { pt } else { extract_stdout(stdin_raw) }\\n} else {\\n    extract_stdout(stdin_raw)\\n}\\nlet mut discoveries = 0\\n\\n// 간단한 숫자 추출 (stdout에서)\\nlet nums = extract_numbers(stdin_text)\\nlet mut exact_names = \\'\\'\\n\\nfor v in nums {\\n    let name = n6_match_name(v)\\n    if name != \\'\\' {\\n        let grade = n6_match_grade(v)\\n        record_discovery(v, name, grade, \\'hexa-hook:\\' + mode)\\n        discoveries = discoveries + 1\\n        if exact_names != \\'\\' {\\n            exact_names = exact_names + \\',\\'\\n        }\\n        exact_names = exact_names + to_string(v) + \\'=\\' + name\\n    }\\n}\\n\\n// ─── hexa 컴파일/런타임 에러 감지 → pitfalls 자동 추가 ───\\nif stdin_text.contains(\\'error[Syntax]\\') || stdin_text.contains(\\'error[Runtime]\\') || stdin_text.contains(\\'error[Type]\\') {\\n    let pitfalls_log = _shared + \\'/hexa_pitfalls_log.jsonl\\'\\n    // 에러 메시지 추출 (첫 줄)\\n    let mut err_msg = \\'\\'\\n    let err_lines = stdin_text.split(\\'\\\\n\\')\\n    let mut ei: i64 = 0\\n    while ei < err_lines.len() {\\n        let el = err_lines[ei]\\n        if el.contains(\\'error[\\') {\\n            err_msg = el.trim()\\n            ei = err_lines.len()\\n        }\\n        ei = ei + 1\\n    }\\n    if err_msg != \\'\\' {\\n        let ts = exec(\\'date +%Y-%m-%dT%H:%M:%S\\').trim()\\n        let entry = \\'{\\\\\\'timestamp\\\\\\':\\\\\\'\\' + ts + \\'\\\\\\',\\\\\\'error\\\\\\':\\\\\\'\\' + err_msg.replace(\\'\\\\\\'\\', \\''\\') + \\'\\\\\\',\\\\\\'mode\\\\\\':\\\\\\'\\' + mode + \\'\\\\\\',\\\\\\'auto_pitfall\\\\\\':true}\\'\\n        try { append_file(pitfalls_log, entry + \\'\\\\n\\') } catch e {}\\n        // systemMessage로 pitfall 추가 알림\\n        let pit_msg = \\'{\\\\\\'systemMe