{'_source': 'pitfalls', '_kind': 'pitfall', '_raw': '{\'timestamp\':\'2026-04-10T02:12:02\',\'error\':\'{'session_id':'274dddea-8d67-4e09-982d-0e03d5ef4d36','transcript_path':'/Users/ghost/.claude-claude3/projects/-Users-ghost-Dev-hexa-lang/274dddea-8d67-4e09-982d-0e03d5ef4d36.jsonl','cwd':'/Users/ghost/Dev/hexa-lang','permission_mode':'bypassPermissions','hook_event_name':'PostToolUse','tool_name':'Write','tool_input':{'file_path':'/Users/ghost/Dev/hexa-lang/self/grammar_autofix.hexa','content':'// self/grammar_autofix.hexa — Hexa 문법 오류 자동 감지+수정\\n// Claude Code PostToolUse hook에서 호출\\n// 사용: hexa self/grammar_autofix.hexa <file.hexa> <error_output>\\n//   또는 파이프: hexa run file.hexa 2>&1 | hexa self/grammar_autofix.hexa --stdin\\n\\nlet args = argv()\\nif len(args) < 2 {\\n    eprintln(\\'usage: grammar_autofix.hexa <file> [error_text]\\')\\n    eprintln(\\'       grammar_autofix.hexa --scan <dir>\\')\\n    exit(1)\\n}\\n\\nlet mode = args[1]\\n\\n// ── 패턴 정의 ──────────────────────────────────────────\\n// 각 패턴: [id, regex_hint, description, auto_fixable]\\nlet patterns = [\\n    [\\'G1\\', \\'-> (\\', \\'튜플 반환타입 -> (T, T)\\', false],\\n    [\\'G2\\', \\': [\\',  \\'배열 타입 어노테이션 : [T]\\', true],\\n    [\\'G3\\', \\'/*\\',   \\'블록 주석 /* ... */\\', true],\\n    [\\'G4\\', \\';\\',    \\'불필요한 세미콜론\\', true],\\n    [\\'G5\\', \\'if { Struct{}\\', \\'if 블록 내 struct literal 충돌\\', false]\\n]\\n\\n// ── 에러 파싱 ──────────────────────────────────────────\\nfn parse_error(line: string) {\\n    // error[Syntax]: message --> file:line:col\\n    let mut file = \\'\\'\\n    let mut msg = \\'\\'\\n    let mut err_line = 0\\n    let mut err_col = 0\\n\\n    if contains(line, \\'-->\\') {\\n        let parts = split(line, \\'-->\\')\\n        if len(parts) >= 2 {\\n            msg = trim(parts[0])\\n            let loc = trim(parts[1])\\n            let loc_parts = split(loc, \\':\\')\\n            if len(loc_parts) >= 3 {\\n                file = loc_parts[0]\\n                err_line = int(loc_parts[1])\\n                err_col = int(loc_parts[2])\\n            }\\n        }\\n    }\\n    return [file, msg, str(err_line), str(err_col)]\\n}\\n\\n// ── 자동 수정 함수들 ──────────────────────────────────\\nfn fix_block_comments(source: string) {\\n    // /* ... */ 제거 (중첩 미지원, 단순 패턴)\\n    let mut result = source\\n    let mut i = 0\\n    let mut out = \\'\\'\\n    let mut in_comment = false\\n    let mut depth = 0\\n\\n    while i < len(result) {\\n        if i + 1 < len(result) {\\n            if result[i] == \\'/\\' && result[i + 1] == \\'*\\' {\\n                depth = depth + 1\\n                in_comment = true\\n                i = i + 2\\n                continue\\n            }\\n            if result[i] == \\'*\\' && result[i + 1] == \\'/\\' {\\n                depth = depth - 1\\n                if depth == 0 { in_comment = false }\\n                i = i + 2\\n                continue\\n            }\\n        }\\n        if !in_comment {\\n            out = out + result[i]\\n        }\\n        i = i + 1\\n    }\\n    return out\\n}\\n\\nfn fix_semicolons(source: string) {\\n    // 줄 끝 세미콜론 제거\\n    let lines = split(source, \\'\\\\n\\')\\n    let mut fixed = []\\n    for line in lines {\\n        let trimmed = trim(line)\\n        if ends_with(trimmed, \\';\\') {\\n            // for 루프 안의 세미콜론은 유지 (C-style for)\\n            if !contains(line, \\'for \\') {\\n                let without = slice(trimmed, 0, len(trimmed) - 1)\\n                // 원본 들여쓰기 유지\\n                let indent = len(line) - len(trim_start(line))\\n                let spaces = repeat(\\' \\', indent)\\n                fixed = push(fixed, spaces + without)\\n                continue\\n            }\\n        }\\n        fixed = push(fixed, line)\\n    }\\n    return join(fixed, \\'\\\\n\\')\\n}\\n\\nfn fix_array_type(source: string) {\\n    // \\': [int]\\' -> \\': array\\'  (파서가 아직 미지원일 때 우회)\\n    let mut result = source\\n    result = replace(result, \\': [int