y\\')\\n    }\\n\\n    if len(fixes) > 0 {\\n        write_file(file, fixed)\\n        print(\\'🔧 \\' + file + \\' → \\' + join(fixes, \\', \\'))\\n    } else {\\n        print(\\'✅ \\' + file + \\' — 이슈 없음\\')\\n    }\\n    exit(0)\\n}\\n\\nif mode == \\'--fix-all\\' {\\n    // 디렉토리 전체 자동 수정\\n    let dir = args[2]\\n    let files = glob(dir + \\'/*.hexa\\')\\n    let mut total_fixes = 0\\n\\n    for file in files {\\n        let source = read_file(file)\\n        let mut fixed = source\\n        let mut fixes = []\\n\\n        if contains(fixed, \\'/*\\') {\\n            fixed = fix_block_comments(fixed)\\n            fixes = push(fixes, \\'G3\\')\\n        }\\n        if contains(fixed, \\';\\') {\\n            fixed = fix_semicolons(fixed)\\n            fixes = push(fixes, \\'G4\\')\\n        }\\n        if contains(fixed, \\': [\\') {\\n            fixed = fix_array_type(fixed)\\n            fixes = push(fixes, \\'G2\\')\\n        }\\n\\n        if len(fixes) > 0 {\\n            write_file(file, fixed)\\n            print(\\'🔧 \\' + file + \\' → \\' + join(fixes, \\', \\'))\\n            total_fixes = total_fixes + 1\\n        }\\n    }\\n    print(\\'\\\\n총 \\' + str(total_fixes) + \\' 파일 수정 완료\\')\\n    exit(0)\\n}\\n\\n// 기본: 에러 텍스트 분석\\nlet file = args[1]\\nlet error_text = if len(args) >= 3 { args[2] } else { \\'\\' }\\n\\nif error_text != \\'\\' {\\n    let info = parse_error(error_text)\\n    let err_file = info[0]\\n    let err_msg = info[1]\\n\\n    // 자동 수정 가능한 패턴 감지\\n    if contains(err_msg, \\'Semicolon\\') {\\n        print(\\'🔧 G4 autofix: semicolon → \\' + err_file)\\n        let src = read_file(err_file)\\n        write_file(err_file, fix_semicolons(src))\\n    } else if contains(err_msg, \\'block comment\\') || contains(err_msg, \\'/*\\') {\\n        print(\\'🔧 G3 autofix: block comment → \\' + err_file)\\n        let src = read_file(err_file)\\n        write_file(err_file, fix_block_comments(src))\\n    } else if contains(err_msg, \\'-> (\\')